"use client";

import { useCallback, useEffect, useRef, useState, useSyncExternalStore } from "react";
import {
  AbstractChat,
  DefaultChatTransport,
  UIMessage,
  ChatState,
  ChatStatus,
} from "ai";

// ---------------------------------------------------------------------------
// Minimal useChat implementation built on AbstractChat + DefaultChatTransport
// ---------------------------------------------------------------------------

class ReactChat extends AbstractChat<UIMessage> {
  private subscribers = new Set<() => void>();

  constructor(api: string) {
    const transport = new DefaultChatTransport({ api });

    // Build the reactive ChatState that notifies React on every mutation
    let internalMessages: UIMessage[] = [];
    let internalStatus: ChatStatus = "ready";
    let internalError: Error | undefined = undefined;

    const notify = () => {
      for (const sub of subscribers) sub();
    };

    const subscribers = new Set<() => void>();

    const state: ChatState<UIMessage> = {
      get status() {
        return internalStatus;
      },
      get error() {
        return internalError;
      },
      get messages() {
        return internalMessages;
      },
      pushMessage(message) {
        internalMessages = [...internalMessages, message];
        notify();
      },
      popMessage() {
        internalMessages = internalMessages.slice(0, -1);
        notify();
      },
      replaceMessage(index, message) {
        internalMessages = [
          ...internalMessages.slice(0, index),
          message,
          ...internalMessages.slice(index + 1),
        ];
        notify();
      },
      snapshot<T>(thing: T): T {
        return thing;
      },
    };

    super({ transport, state });

    this.subscribers = subscribers;

    // Intercept setStatus so we notify React when status/error changes
    const origSetStatus = (this as unknown as { setStatus: (args: { status: ChatStatus; error?: Error }) => void }).setStatus.bind(this);
    (this as unknown as { setStatus: (args: { status: ChatStatus; error?: Error }) => void }).setStatus = (args) => {
      origSetStatus(args);
      notify();
    };
  }

  subscribe(callback: () => void) {
    this.subscribers.add(callback);
    return () => {
      this.subscribers.delete(callback);
    };
  }

  getSnapshot() {
    return {
      messages: this.messages,
      status: this.status,
      error: this.error,
    };
  }
}

function useChat(api: string = "/api/chat") {
  const chatRef = useRef<ReactChat | null>(null);
  if (!chatRef.current) {
    chatRef.current = new ReactChat(api);
  }
  const chat = chatRef.current;

  const snapshot = useSyncExternalStore(
    useCallback((cb) => chat.subscribe(cb), [chat]),
    useCallback(() => chat.getSnapshot(), [chat]),
    useCallback(() => chat.getSnapshot(), [chat]),
  );

  const [input, setInput] = useState("");

  const handleSubmit = useCallback(
    async (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      const text = input.trim();
      if (!text) return;
      setInput("");
      await chat.sendMessage({ text });
    },
    [chat, input],
  );

  return {
    messages: snapshot.messages,
    status: snapshot.status,
    error: snapshot.error,
    input,
    setInput,
    handleSubmit,
  };
}

