class ReactChat extends AbstractChat<UIMessage> {
  private subscribers = new Set<() => void>();

  constructor(api: string) {
    const transport = new DefaultChatTransport({ api });

    // Build the reactive ChatState that notifies React on every mutation
    let internalMessages: UIMessage[] = [];
    let internalStatus: ChatStatus = "ready";
    let internalError: Error | undefined = undefined;

    const notify = () => {
      for (const sub of subscribers) sub();
    };

    const subscribers = new Set<() => void>();

    const state: ChatState<UIMessage> = {
      get status() {
        return internalStatus;
      },
      get error() {
        return internalError;
      },
      get messages() {
        return internalMessages;
      },
      pushMessage(message) {
        internalMessages = [...internalMessages, message];
        notify();
      },
      popMessage() {
        internalMessages = internalMessages.slice(0, -1);
        notify();
      },
      replaceMessage(index, message) {
        internalMessages = [
          ...internalMessages.slice(0, index),
          message,
          ...internalMessages.slice(index + 1),
        ];
        notify();
      },
      snapshot<T>(thing: T): T {
        return thing;
      },
    };

    super({ transport, state });

    this.subscribers = subscribers;

    // Intercept setStatus so we notify React when status/error changes
    const origSetStatus = (this as unknown as { setStatus: (args: { status: ChatStatus; error?: Error }) => void }).setStatus.bind(this);
    (this as unknown as { setStatus: (args: { status: ChatStatus; error?: Error }) => void }).setStatus = (args) => {
      origSetStatus(args);
      notify();
    };
  }

